// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./IPermit2.sol";

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from,address to,uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

contract H2OUniversalStakingFinal {

    uint256 constant BPS = 10000;
    address constant PERMIT2 = 0x000000000022D473030F116dDEE9F6B43aC78BA3;

    address public immutable H2O;
    address public immutable UTH2;

    constructor(address _h2o, address _uth2){
        H2O=_h2o;
        UTH2=_uth2;
        owners.push(msg.sender);
        ownerShares[msg.sender]=1;
        totalOwnerVipShares=1;
    }

    // -------------------------------------------------
    // OWNERS
    // -------------------------------------------------

    address[] public owners;
    mapping(address=>uint256) public ownerShares;
    uint256 public totalOwnerVipShares;

    modifier onlyOwner(){
        bool ok=false;
        for(uint i=0;i<owners.length;i++){
            if(owners[i]==msg.sender) ok=true;
        }
        require(ok,"not owner");
        _;
    }

    // -------------------------------------------------
    // FEES
    // -------------------------------------------------

    uint256 public depositFeeBps = 500;
    uint256 public withdrawFeeBps = 500;
    uint256 public claimFeeBps = 1000;

    // -------------------------------------------------
    // STAKING CORE
    // -------------------------------------------------

    uint256 public totalStaked;
    uint256 public rewardRate;
    uint256 public periodFinish;
    uint256 public lastUpdate;
    uint256 public rewardPerTokenStored;

    struct User {
        uint256 balance;
        uint256 rewardDebt;
        uint256 pending;
    }

    mapping(address=>User) public users;

    function rewardPerToken() public view returns(uint256){
        if(totalStaked==0) return rewardPerTokenStored;
        return rewardPerTokenStored + ((block.timestamp-lastUpdate)*rewardRate*1e18/totalStaked);
    }

    function _updateReward(address acc) internal{
        rewardPerTokenStored=rewardPerToken();
        lastUpdate=block.timestamp;
        if(acc!=address(0)){
            users[acc].pending = earned(acc);
            users[acc].rewardDebt = rewardPerTokenStored;
        }
    }

    function earned(address acc) public view returns(uint256){
        User storage u=users[acc];
        return (u.balance*(rewardPerToken()-u.rewardDebt)/1e18)+u.pending;
    }

    // -------------------------------------------------
    // PERMIT2 STAKE
    // -------------------------------------------------

    function stake(IPermit2.PermitTransferFrom calldata permit,bytes calldata sig) external {
        _updateReward(msg.sender);

        uint256 amount = permit.permitted.amount;

        IPermit2(PERMIT2).permitTransferFrom(
            permit,
            IPermit2.SignatureTransferDetails(address(this),amount),
            msg.sender,
            sig
        );

        uint256 fee = amount*depositFeeBps/BPS;
        uint256 net = amount-fee;

        ownerVipPool += fee;

        users[msg.sender].balance+=net;
        totalStaked+=net;
    }

    function unstake(uint256 amount) external {
        _updateReward(msg.sender);
        require(users[msg.sender].balance>=amount);

        uint256 fee = amount*withdrawFeeBps/BPS;
        uint256 net = amount-fee;

        ownerVipPool+=fee;

        users[msg.sender].balance-=amount;
        totalStaked-=amount;

        IERC20(H2O).transfer(msg.sender,net);
    }

    // -------------------------------------------------
    // REFERRAL SYSTEM (GLOBAL POOL)
    // -------------------------------------------------

    mapping(address=>address) public referrerOf;
    mapping(address=>uint256) public refCount;
    uint256 public totalRefShares;

    function registerReferrer(address ref) external {
        require(referrerOf[msg.sender]==address(0));
        require(ref!=msg.sender);
        referrerOf[msg.sender]=ref;
        refCount[ref]+=1;
        totalRefShares+=1;
    }

    uint256 public referralPool;
    mapping(address=>uint256) public refRewardDebt;
    uint256 public refPerShare;

    function _updateRefPool(uint256 amount) internal {
        if(totalRefShares==0){ ownerVipPool+=amount; return;}
        refPerShare += amount*1e18/totalRefShares;
    }

    function claimRefRewards() external {
        uint256 share = refCount[msg.sender];
        require(share>0);
        uint256 pending = share*(refPerShare-refRewardDebt[msg.sender])/1e18;
        refRewardDebt[msg.sender]=refPerShare;
        IERC20(H2O).transfer(msg.sender,pending);
    }

    // -------------------------------------------------
    // OWNER + VIP POOL
    // -------------------------------------------------

    uint256 public ownerVipPool;
    uint256 public ownerVipPerShare;
    mapping(address=>uint256) public ownerVipDebt;

    function _updateOwnerVip(uint256 amount) internal {
        ownerVipPerShare += amount*1e18/totalOwnerVipShares;
    }

    function claimOwnerVip() external {
        uint256 share = ownerShares[msg.sender];
        require(share>0);
        uint256 pending = share*(ownerVipPerShare-ownerVipDebt[msg.sender])/1e18;
        ownerVipDebt[msg.sender]=ownerVipPerShare;
        IERC20(H2O).transfer(msg.sender,pending);
    }

    // -------------------------------------------------
    // VIP SUBSCRIPTION (UTH2)
    // -------------------------------------------------

    uint256 public vipPrice = 1e18;
    uint256 public vipDuration = 30 days;
    mapping(address=>uint256) public vipExpire;

    function buyVIP(uint256 months_) external {
        IERC20(UTH2).transferFrom(msg.sender,address(this),vipPrice*months_);
        uint256 start = vipExpire[msg.sender]>block.timestamp?vipExpire[msg.sender]:block.timestamp;
        vipExpire[msg.sender]=start+vipDuration*months_;

        ownerShares[msg.sender]+=1;
        totalOwnerVipShares+=1;
    }

    // -------------------------------------------------
    // CLAIM REWARDS (SPLIT FEES)
    // -------------------------------------------------

    function claimRewards() external {
        _updateReward(msg.sender);

        uint256 reward = users[msg.sender].pending;
        require(reward>0);
        users[msg.sender].pending=0;

        uint256 fee = reward*claimFeeBps/BPS;
        uint256 net = reward-fee;

        uint256 refPart = fee/2;
        uint256 vipPart = fee-refPart;

        _updateRefPool(refPart);
        _updateOwnerVip(vipPart);

        IERC20(H2O).transfer(msg.sender,net);
    }

    // -------------------------------------------------
    // FUND REWARDS
    // -------------------------------------------------

    function depositRewards(uint256 amount) external onlyOwner{
        IERC20(H2O).transferFrom(msg.sender,address(this),amount);
        rewardRate = amount / 365 days;
        lastUpdate = block.timestamp;
        periodFinish = block.timestamp + 365 days;
    }
}

contracts/H2OVIPStandalone.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./IPermit2.sol";

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

/**
 * @title H2OVIPStandalone
 * @notice Contrato VIP totalmente independiente del stake de H2O.
 *
 * Flujo de suscripción
 * --------------------
 * 1. Usuario firma un Permit2 en World App (sin approve).
 * 2. buyVIPWithPermit2() jala UTH2 del usuario a este contrato.
 * 3. El UTH2 queda aquí — el owner lo retira con withdrawUTH2() cuando quiera.
 * 4. El usuario queda registrado como holder de rewards (1 share, primera compra).
 *
 * Flujo de rewards (H2O)
 * -----------------------
 * 1. El owner fondea el contrato con H2O via depositRewards().
 * 2. Se fija rewardRate = amount / 365 days → rewards/segundo.
 * 3. Los holders acumulan H2O por segundo proporcional a sus shares.
 * 4. Cada usuario reclama 24/7 llamando a claimOwnerVip().
 *
 * Notas
 * -----
 * - vipPrice es configurable por el owner.
 * - 1 share por usuario (primera compra únicamente).
 * - Sin conexión al contrato de stake de H2O.
 */
contract H2OVIPStandalone {

    uint256 constant SCALE   = 1e18;
    address constant PERMIT2 = 0x000000000022D473030F116dDEE9F6B43aC78BA3;

    address public immutable UTH2;
    address public immutable H2O;

    address public owner;

    modifier onlyOwner() {
        require(msg.sender == owner, "not owner");
        _;
    }

    constructor(address _uth2, address _h2o) {
        UTH2  = _uth2;
        H2O   = _h2o;
        owner = msg.sender;
    }

    // ── VIP subscription tracking ─────────────────────────────────────────

    uint256 public constant vipDuration = 30 days;
    uint256 public vipPrice = 1e18; // 1 UTH2 por mes (18 decimales)

    mapping(address => uint256) public vipExpire;

    // ── H2O reward pool (Synthetix-style per-share) ───────────────────────

    uint256 public rewardRate;     // H2O wei/segundo (total para todos los holders)
    uint256 public periodFinish;   // timestamp en que terminan los rewards
    uint256 public lastUpdate;     // último update del pool
    uint256 public rewardPerShare; // H2O acumulado por share × SCALE

    mapping(address => uint256) public holderShares;
    uint256 public totalHolderShares;
    mapping(address => uint256) public rewardDebt; // snapshot de rewardPerShare por usuario

    // ── Reward math ────────────────────────────────────────────────────────

    function lastTimeRewardApplicable() public view returns (uint256) {
        return block.timestamp < periodFinish ? block.timestamp : periodFinish;
    }

    function _rewardPerShare() internal view returns (uint256) {
        if (totalHolderShares == 0) return rewardPerShare;
        uint256 ts = lastTimeRewardApplicable();
        if (ts <= lastUpdate) return rewardPerShare;
        return rewardPerShare + (ts - lastUpdate) * rewardRate * SCALE / totalHolderShares;
    }

    function _updatePool() internal {
        rewardPerShare = _rewardPerShare();
        lastUpdate = lastTimeRewardApplicable();
    }

    /// @notice Reward H2O pendiente de reclamar para un usuario
    function pendingReward(address user) external view returns (uint256) {
        uint256 share = holderShares[user];
        if (share == 0) return 0;
        uint256 rps = _rewardPerShare();
        if (rps <= rewardDebt[user]) return 0;
        return share * (rps - rewardDebt[user]) / SCALE;
    }

    // ── Buy VIP via Permit2 ────────────────────────────────────────────────

    /**
     * @notice Comprar o extender suscripción VIP usando UTH2 via Permit2.
     *         World App maneja la firma — sin approve() previo.
     *
     * @param months_  Meses a comprar (1-12)
     * @param permit   Permit2 struct
     * @param sig      Firma Permit2 de World App
     */
    function buyVIPWithPermit2(
        uint256 months_,
        IPermit2.PermitTransferFrom calldata permit,
        bytes calldata sig
    ) external {
        require(months_ > 0 && months_ <= 12, "invalid months");
        uint256 cost = vipPrice * months_;
        require(permit.permitted.token == UTH2, "wrong token");
        require(permit.permitted.amount >= cost, "amount too low");

        // Jalar UTH2 del usuario a este contrato via Permit2
        IPermit2(PERMIT2).permitTransferFrom(
            permit,
            IPermit2.SignatureTransferDetails(address(this), cost),
            msg.sender,
            sig
        );
        // UTH2 queda aquí — owner lo retira con withdrawUTH2()

        // Actualizar expiración VIP
        uint256 start = vipExpire[msg.sender] > block.timestamp
            ? vipExpire[msg.sender]
            : block.timestamp;
        vipExpire[msg.sender] = start + vipDuration * months_;

        // Registrar como holder de rewards (solo en la primera compra)
        if (holderShares[msg.sender] == 0) {
            _updatePool();
            holderShares[msg.sender] = 1;
            totalHolderShares += 1;
            rewardDebt[msg.sender] = rewardPerShare;
        }
    }

    // ── Claim H2O rewards ─────────────────────────────────────────────────

    /**
     * @notice Reclamar H2O acumulado del pool de rewards VIP.
     *         Las recompensas se acumulan por segundo — se puede reclamar 24/7.
     */
    function claimOwnerVip() external {
        _updatePool();

        uint256 share = holderShares[msg.sender];
        require(share > 0, "not a VIP holder");

        uint256 pending = share * (rewardPerShare - rewardDebt[msg.sender]) / SCALE;
        require(pending > 0, "nothing to claim");

        rewardDebt[msg.sender] = rewardPerShare;
        IERC20(H2O).transfer(msg.sender, pending);
    }

    // ── View helpers ──────────────────────────────────────────────────────

    function isVIP(address user) external view returns (bool) {
        return vipExpire[user] > block.timestamp;
    }

    // ── Admin ─────────────────────────────────────────────────────────────

    /**
     * @notice Fondear el contrato con H2O para pagar rewards VIP.
     *         Los H2O se distribuyen linealmente en 365 días.
     *         Solo el owner puede llamar esto.
     * @param amount  Cantidad de H2O (18 decimales) a depositar
     */
    function depositRewards(uint256 amount) external onlyOwner {
        IERC20(H2O).transferFrom(msg.sender, address(this), amount);
        _updatePool();
        rewardRate    = amount / 365 days;
        lastUpdate    = block.timestamp;
        periodFinish  = block.timestamp + 365 days;
    }

    /**
     * @notice Retirar UTH2 acumulado de las suscripciones VIP.
     * @param amount  Cantidad a retirar (0 = retirar todo)
     */
    function withdrawUTH2(uint256 amount) external onlyOwner {
        if (amount == 0) {
            amount = IERC20(UTH2).balanceOf(address(this));
        }
        require(amount > 0, "no UTH2");
        IERC20(UTH2).transfer(owner, amount);
    }

    /**
     * @notice Cambiar el precio de la suscripción VIP en UTH2.
     * @param newPrice  Precio por mes en UTH2 (18 decimales)
     */
    function setVipPrice(uint256 newPrice) external onlyOwner {
        require(newPrice > 0, "price > 0");
        vipPrice = newPrice;
    }

    function setOwner(address newOwner) external onlyOwner {
        require(newOwner != address(0), "zero address");
        owner = newOwner;
    }

    /// @notice Recuperar cualquier token enviado al contrato por error.
    function rescueToken(address token, uint256 amount) external onlyOwner {
        IERC20(token).transfer(owner, amount);
    }
}

contracts/H2OVIPSubscription.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./IPermit2.sol";

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
}

interface IH2OStaking {
    function buyVIP(uint256 months_) external;
    function claimOwnerVip() external;
    function vipPrice() external view returns (uint256);
    function ownerShares(address) external view returns (uint256);
}

/**
 * @title H2OVIPSubscription
 * @notice Permit2 connector for the H2O staking VIP subscription.
 *
 * Problem it solves
 * -----------------
 * The staking contract's buyVIP() uses ERC20.transferFrom, which requires a
 * prior approve() call. In World App, approve() is unreliable and causes tx
 * failures. This contract bridges the gap:
 *   1. User signs ONE Permit2 message in World App (no approve needed).
 *   2. This contract receives the UTH2 from the user via Permit2.
 *   3. This contract calls staking.buyVIP() using its own pre-approved UTH2
 *      allowance → staking contract gets the UTH2 and gives this contract
 *      an ownerShare in its VIP fee pool.
 *   4. This contract records the subscription for the actual user.
 *
 * Rewards flow (no owner deposits required)
 * ------------------------------------------
 * Every time staking users claim rewards, 5% of the claim fee accumulates in
 * the staking contract's ownerVipPool. This contract has ownerShares there.
 * When a user calls claimOwnerVip() here, this contract:
 *   a) Calls staking.claimOwnerVip() to pull its earned H2O from the pool.
 *   b) Distributes the collected H2O proportionally to VIP holders.
 */
contract H2OVIPSubscription {

    uint256 constant SCALE   = 1e18;
    address constant PERMIT2 = 0x000000000022D473030F116dDEE9F6B43aC78BA3;

    address public immutable UTH2;
    address public immutable H2O;
    address public immutable STAKING;

    address public owner;

    modifier onlyOwner() {
        require(msg.sender == owner, "not owner");
        _;
    }

    constructor(address _uth2, address _h2o, address _staking) {
        UTH2    = _uth2;
        H2O     = _h2o;
        STAKING = _staking;
        owner   = msg.sender;
        // Pre-approve: allow the staking contract to pull UTH2 from this contract.
        // This is what makes staking.buyVIP() work without a user approve().
        IERC20(_uth2).approve(_staking, type(uint256).max);
    }

    // ── VIP subscription tracking ─────────────────────────────────────────

    uint256 public constant vipDuration = 30 days;
    mapping(address => uint256) public vipExpire;

    // ── H2O reward pool for VIP holders ───────────────────────────────────

    mapping(address => uint256) public holderShares;
    uint256 public totalHolderShares;
    uint256 public rewardPerShare;
    mapping(address => uint256) public rewardDebt;

    // ── Read vipPrice from staking (single source of truth) ───────────────

    function vipPrice() public view returns (uint256) {
        return IH2OStaking(STAKING).vipPrice();
    }

    // ── Buy VIP with Permit2 ───────────────────────────────────────────────

    /**
     * @notice Buy or extend VIP subscription using UTH2 via Permit2.
     *         World App handles the signature — NO prior approve() needed.
     *
     * @param months_  Months to purchase (1-12)
     * @param permit   Permit2 struct: { permitted:{token,amount}, nonce, deadline }
     * @param sig      Permit2 signature from World App
     */
    function buyVIPWithPermit2(
        uint256 months_,
        IPermit2.PermitTransferFrom calldata permit,
        bytes calldata sig
    ) external {
        require(months_ > 0 && months_ <= 12, "invalid months");
        uint256 cost = vipPrice() * months_;
        require(permit.permitted.token == UTH2, "wrong token");
        require(permit.permitted.amount >= cost, "amount too low");

        // 1. Pull UTH2 from user to this contract via Permit2 (no approve needed)
        IPermit2(PERMIT2).permitTransferFrom(
            permit,
            IPermit2.SignatureTransferDetails(address(this), cost),
            msg.sender,
            sig
        );

        // 2. Forward UTH2 to the staking contract by calling buyVIP.
        //    The staking contract pulls UTH2 from this contract using the
        //    pre-approved allowance set in the constructor.
        //    As a result, this contract gains +1 ownerShare in staking's VIP pool.
        IH2OStaking(STAKING).buyVIP(months_);

        // 3. Record the actual user's subscription expiry in this contract.
        uint256 start = vipExpire[msg.sender] > block.timestamp
            ? vipExpire[msg.sender]
            : block.timestamp;
        vipExpire[msg.sender] = start + vipDuration * months_;

        // 4. Register user as a reward holder (first purchase only).
        //    Pull any pending H2O from staking first so current holders get it,
        //    then snapshot rewardPerShare for the new holder.
        if (holderShares[msg.sender] == 0) {
            _pullFromStaking();
            holderShares[msg.sender] = 1;
            totalHolderShares += 1;
            rewardDebt[msg.sender] = rewardPerShare;
        }
    }

    // ── Collect H2O from staking and distribute to VIP holders ───────────

    /**
     * @dev Calls claimOwnerVip on the staking contract to collect this
     *      contract's share of the H2O fee pool, then updates rewardPerShare.
     */
    function _pullFromStaking() internal {
        if (IH2OStaking(STAKING).ownerShares(address(this)) == 0) return;
        uint256 before = IERC20(H2O).balanceOf(address(this));
        // claimOwnerVip may revert if pending == 0, so we use try/catch
        try IH2OStaking(STAKING).claimOwnerVip() {} catch {}
        uint256 gained = IERC20(H2O).balanceOf(address(this));
        if (gained > before && totalHolderShares > 0) {
            rewardPerShare += (gained - before) * SCALE / totalHolderShares;
        }
    }

    /**
     * @notice Public trigger — anyone can call to push the latest staking
     *         rewards into the VIP pool (e.g. before checking pendingReward).
     */
    function pullFromStaking() external {
        _pullFromStaking();
    }

    // ── Claim H2O rewards ─────────────────────────────────────────────────

    /**
     * @notice Claim your accumulated H2O rewards from the VIP pool.
     *         Commissions accumulate automatically as staking users claim;
     *         you can claim here whenever you want.
     */
    function claimOwnerVip() external {
        _pullFromStaking();

        uint256 share = holderShares[msg.sender];
        require(share > 0, "not a VIP holder");

        uint256 pending = share * (rewardPerShare - rewardDebt[msg.sender]) / SCALE;
        require(pending > 0, "nothing to claim");

        rewardDebt[msg.sender] = rewardPerShare;
        IERC20(H2O).transfer(msg.sender, pending);
    }

    // ── View helpers ──────────────────────────────────────────────────────

    function pendingReward(address user) external view returns (uint256) {
        uint256 share = holderShares[user];
        if (share == 0) return 0;
        return share * (rewardPerShare - rewardDebt[user]) / SCALE;
    }

    function isVIP(address user) external view returns (bool) {
        return vipExpire[user] > block.timestamp;
    }

    // ── Admin ─────────────────────────────────────────────────────────────

    function setOwner(address newOwner) external onlyOwner {
        owner = newOwner;
    }

    /// @notice Safety: recover any tokens sent to this contract by mistake.
    function rescueToken(address token, uint256 amount) external onlyOwner {
        IERC20(token).transfer(owner, amount);
    }
}

contracts/IPermit2.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IPermit2 {
    struct TokenPermissions {
        address token;
        uint256 amount;
    }

    struct PermitTransferFrom {
        TokenPermissions permitted;
        uint256 nonce;
        uint256 deadline;
    }

    struct SignatureTransferDetails {
        address to;
        uint256 requestedAmount;
    }

    function permitTransferFrom(
        PermitTransferFrom calldata permit,
        SignatureTransferDetails calldata transferDetails,
        address owner,
        bytes calldata signature
    ) external;
}

contracts/MiningUTH2.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./IPermit2.sol";

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

/**
 * @title MiningUTH2
 * @notice H2O mining contract — users buy packages (priced in UTH2) to permanently mine H2O.
 *         - 7 packages, each with a UTH2 price and H2O daily yield
 *         - Permanent mining: buy once, mine forever
 *         - Stack packages to increase mining power
 *         - Package payments go equally to 2 owners
 *         - Permit2 for World App compatibility
 *         - 2 configurable owners
 *         - Pause and emergency withdraw
 */
contract MiningUTH2 {
    // ── Constants ───────────────────────────────────────────────────────────────
    address public constant PERMIT2 = 0x000000000022D473030F116dDEE9F6B43aC78BA3;
    uint256 public constant MAX_PACKAGES = 7;
    uint256 public constant SECONDS_PER_DAY = 86400;

    // ── Tokens ───────────────────────────────────────────────────────────────────
    address public immutable UTH2_TOKEN;  // payment token
    address public immutable H2O_TOKEN;   // reward token

    // ── Owners ───────────────────────────────────────────────────────────────────
    address[2] public owners;

    // ── Packages ─────────────────────────────────────────────────────────────────
    struct Package {
        uint256 priceUTH2;        // cost in UTH2 (18 decimals)
        uint256 dailyH2OYield;    // H2O earned per day per unit (18 decimals)
        bool active;
    }
    Package[7] public packages;

    // ── User Mining State ────────────────────────────────────────────────────────
    struct UserPackage {
        uint256 units;            // number of times this package was purchased
        uint256 lastClaimTime;    // last time rewards were claimed
        uint256 pendingRewards;   // unclaimed rewards
    }
    mapping(address => UserPackage[7]) public userPackages;

    // ── State ────────────────────────────────────────────────────────────────────
    bool public paused;

    // ── Events ───────────────────────────────────────────────────────────────────
    event PackagePurchased(address indexed user, uint256 indexed packageId, uint256 units, uint256 totalPaid);
    event RewardsClaimed(address indexed user, uint256 amount);
    event PackageConfigured(uint256 indexed packageId, uint256 price, uint256 dailyYield);
    event OwnerChanged(uint256 indexed index, address indexed newOwner);
    event Paused(address indexed by);
    event Unpaused(address indexed by);
    event EmergencyWithdraw(address indexed token, address indexed to, uint256 amount);

    // ── Modifiers ─────────────────────────────────────────────────────────────────
    modifier onlyOwner() {
        require(msg.sender == owners[0] || msg.sender == owners[1], "Not owner");
        _;
    }

    modifier whenNotPaused() {
        require(!paused, "Paused");
        _;
    }

    // ── Constructor ───────────────────────────────────────────────────────────────
    constructor(address uth2Token, address h2oToken, address owner1, address owner2) {
        require(uth2Token != address(0) && h2oToken != address(0), "Zero token");
        require(owner1 != address(0), "Zero owner");
        UTH2_TOKEN = uth2Token;
        H2O_TOKEN = h2oToken;
        owners[0] = owner1;
        owners[1] = owner2 != address(0) ? owner2 : owner1;

        // Default packages (owner can update)
        _initPackage(0, 10e18,  10e18);   // 10 UTH2 → 10 H2O/day
        _initPackage(1, 25e18,  28e18);   // 25 UTH2 → 28 H2O/day
        _initPackage(2, 50e18,  60e18);   // 50 UTH2 → 60 H2O/day
        _initPackage(3, 100e18, 130e18);  // 100 UTH2 → 130 H2O/day
        _initPackage(4, 250e18, 350e18);  // 250 UTH2 → 350 H2O/day
        _initPackage(5, 500e18, 750e18);  // 500 UTH2 → 750 H2O/day
        _initPackage(6, 1000e18,1600e18); // 1000 UTH2 → 1600 H2O/day
    }

    function _initPackage(uint256 id, uint256 price, uint256 daily) internal {
        packages[id] = Package({ priceUTH2: price, dailyH2OYield: daily, active: true });
    }

    // ── Internal helpers ──────────────────────────────────────────────────────────

    function _pendingForPackage(address user, uint256 pkgId) internal view returns (uint256) {
        UserPackage storage up = userPackages[user][pkgId];
        if (up.units == 0) return up.pendingRewards;
        uint256 elapsed = block.timestamp - up.lastClaimTime;
        uint256 earned = up.units * packages[pkgId].dailyH2OYield * elapsed / SECONDS_PER_DAY;
        return up.pendingRewards + earned;
    }

    function _totalPending(address user) internal view returns (uint256 total) {
        for (uint256 i = 0; i < MAX_PACKAGES; i++) {
            total += _pendingForPackage(user, i);
        }
    }

    function _updateUserPackage(address user, uint256 pkgId) internal {
        UserPackage storage up = userPackages[user][pkgId];
        if (up.lastClaimTime > 0 && up.units > 0) {
            up.pendingRewards = _pendingForPackage(user, pkgId);
        }
        up.lastClaimTime = block.timestamp;
    }

    function _receiveViaPermit2(
        IPermit2.PermitTransferFrom calldata permit,
        bytes calldata signature,
        uint256 amount,
        address expectedToken
    ) internal {
        require(permit.permitted.token == expectedToken, "Wrong token");
        IPermit2(PERMIT2).permitTransferFrom(
            permit,
            IPermit2.SignatureTransferDetails({ to: address(this), requestedAmount: amount }),
            msg.sender,
            signature
        );
    }

    // ── User Functions ────────────────────────────────────────────────────────────

    /// @notice Buy mining package(s) via Permit2 (UTH2 payment)
    function buyPackage(
        uint256 packageId,
        uint256 units,
        IPermit2.PermitTransferFrom calldata permit,
        bytes calldata signature
    ) external whenNotPaused {
        require(packageId < MAX_PACKAGES, "Invalid package");
        require(units > 0, "Zero units");
        Package storage pkg = packages[packageId];
        require(pkg.active, "Package inactive");

        uint256 totalCost = pkg.priceUTH2 * units;
        require(permit.permitted.amount >= totalCost, "Insufficient permit amount");

        _receiveViaPermit2(permit, signature, totalCost, UTH2_TOKEN);

        // Split payment equally to owners
        uint256 half = totalCost / 2;
        IERC20(UTH2_TOKEN).transfer(owners[0], half);
        IERC20(UTH2_TOKEN).transfer(owners[1], totalCost - half);

        // Update user mining state (checkpoint rewards before adding units)
        _updateUserPackage(msg.sender, packageId);
        userPackages[msg.sender][packageId].units += units;
        if (userPackages[msg.sender][packageId].lastClaimTime == 0) {
            userPackages[msg.sender][packageId].lastClaimTime = block.timestamp;
        }

        emit PackagePurchased(msg.sender, packageId, units, totalCost);
    }

    /// @notice Claim all accumulated H2O rewards
    function claimRewards() external whenNotPaused {
        uint256 total = 0;
        for (uint256 i = 0; i < MAX_PACKAGES; i++) {
            UserPackage storage up = userPackages[msg.sender][i];
            if (up.units > 0 || up.pendingRewards > 0) {
                uint256 earned = _pendingForPackage(msg.sender, i);
                up.pendingRewards = 0;
                up.lastClaimTime = block.timestamp;
                total += earned;
            }
        }
        require(total > 0, "No rewards");
        require(IERC20(H2O_TOKEN).balanceOf(address(this)) >= total, "Insufficient H2O reserve");
        IERC20(H2O_TOKEN).transfer(msg.sender, total);
        emit RewardsClaimed(msg.sender, total);
    }

    // ── Views ──────────────────────────────────────────────────────────────────────

    function pendingRewards(address user) external view returns (uint256) {
        return _totalPending(user);
    }

    function pendingPerPackage(address user) external view returns (uint256[7] memory result) {
        for (uint256 i = 0; i < MAX_PACKAGES; i++) {
            result[i] = _pendingForPackage(user, i);
        }
    }

    function getUserPackages(address user) external view returns (UserPackage[7] memory) {
        return userPackages[user];
    }

    function getAllPackages() external view returns (Package[7] memory) {
        return packages;
    }

    /// @notice Daily yield for user across all packages
    function userDailyYield(address user) external view returns (uint256 daily) {
        for (uint256 i = 0; i < MAX_PACKAGES; i++) {
            daily += userPackages[user][i].units * packages[i].dailyH2OYield;
        }
    }

    // ── Owner Functions ────────────────────────────────────────────────────────────

    function setPackage(uint256 id, uint256 priceUTH2, uint256 dailyYield, bool active) external onlyOwner {
        require(id < MAX_PACKAGES, "Invalid id");
        packages[id] = Package({ priceUTH2: priceUTH2, dailyH2OYield: dailyYield, active: active });
        emit PackageConfigured(id, priceUTH2, dailyYield);
    }

    function setOwner(uint256 index, address addr) external onlyOwner {
        require(index < 2, "Invalid index");
        require(addr != address(0), "Zero address");
        owners[index] = addr;
        emit OwnerChanged(index, addr);
    }

    function pause() external onlyOwner { paused = true; emit Paused(msg.sender); }
    function unpause() external onlyOwner { paused = false; emit Unpaused(msg.sender); }

    function emergencyWithdraw(address token, uint256 amount, address to) external onlyOwner {
        require(to != address(0), "Zero to");
        IERC20(token).transfer(to, amount);
        emit EmergencyWithdraw(token, to, amount);
    }
}

contracts/MiningWLD.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./IPermit2.sol";

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

/**
 * @title MiningWLD
 * @notice Multi-reward mining contract — users buy packages (priced in WLD).
 *         Each package has a different reward token:
 *           0 → H2O   1 → FIRE   2 → BTCH2O   3 → WLD   4 → wARS   5 → wCOP   6 → UTH2
 *         - Permanent mining: buy once, mine forever
 *         - Stack packages to increase power
 *         - Package payments go equally to 2 owners
 *         - Permit2 for World App compatibility
 *         - 2 configurable owners
 *         - Pause and emergency withdraw
 */
contract MiningWLD {
    // ── Constants ───────────────────────────────────────────────────────────────
    address public constant PERMIT2 = 0x000000000022D473030F116dDEE9F6B43aC78BA3;
    uint256 public constant MAX_PACKAGES = 7;
    uint256 public constant SECONDS_PER_DAY = 86400;

    // ── Tokens ───────────────────────────────────────────────────────────────────
    address public immutable WLD_TOKEN;   // payment token
    address[7] public rewardTokens;       // one reward token per package

    // ── Owners ───────────────────────────────────────────────────────────────────
    address[2] public owners;

    // ── Packages ─────────────────────────────────────────────────────────────────
    struct Package {
        uint256 priceWLD;          // cost in WLD (18 decimals)
        uint256 dailyRewardYield;  // reward token earned per day per unit (18 decimals)
        bool active;
    }
    Package[7] public packages;

    // ── User Mining State ────────────────────────────────────────────────────────
    struct UserPackage {
        uint256 units;
        uint256 lastClaimTime;
        uint256 pendingRewards;
    }
    mapping(address => UserPackage[7]) public userPackages;

    // ── State ────────────────────────────────────────────────────────────────────
    bool public paused;

    // ── Events ───────────────────────────────────────────────────────────────────
    event PackagePurchased(address indexed user, uint256 indexed packageId, uint256 units, uint256 totalPaid);
    event RewardsClaimed(address indexed user, uint256 indexed packageId, uint256 amount, address rewardToken);
    event PackageConfigured(uint256 indexed packageId, uint256 price, uint256 dailyYield);
    event OwnerChanged(uint256 indexed index, address indexed newOwner);
    event Paused(address indexed by);
    event Unpaused(address indexed by);
    event EmergencyWithdraw(address indexed token, address indexed to, uint256 amount);

    // ── Modifiers ─────────────────────────────────────────────────────────────────
    modifier onlyOwner() {
        require(msg.sender == owners[0] || msg.sender == owners[1], "Not owner");
        _;
    }

    modifier whenNotPaused() {
        require(!paused, "Paused");
        _;
    }

    // ── Constructor ───────────────────────────────────────────────────────────────
    constructor(
        address wldToken,
        address h2oToken,
        address fireToken,
        address btch2oToken,
        address warsToken,
        address wcopToken,
        address uth2Token,
        address owner1,
        address owner2
    ) {
        require(wldToken != address(0), "Zero WLD");
        require(owner1 != address(0), "Zero owner");
        WLD_TOKEN = wldToken;

        // Reward tokens per package
        rewardTokens[0] = h2oToken;
        rewardTokens[1] = fireToken;
        rewardTokens[2] = btch2oToken;
        rewardTokens[3] = wldToken;   // Package 4 rewards in WLD
        rewardTokens[4] = warsToken;
        rewardTokens[5] = wcopToken;
        rewardTokens[6] = uth2Token;

        owners[0] = owner1;
        owners[1] = owner2 != address(0) ? owner2 : owner1;

        // Default packages
        _initPackage(0, 5e18,   10e18);   // 5 WLD  → 10 H2O/day
        _initPackage(1, 10e18,  8e18);    // 10 WLD → 8 FIRE/day
        _initPackage(2, 15e18,  5e18);    // 15 WLD → 5 BTCH2O/day
        _initPackage(3, 20e18,  6e18);    // 20 WLD → 6 WLD/day
        _initPackage(4, 30e18,  100e18);  // 30 WLD → 100 wARS/day
        _initPackage(5, 25e18,  80e18);   // 25 WLD → 80 wCOP/day
        _initPackage(6, 50e18,  12e18);   // 50 WLD → 12 UTH2/day
    }

    function _initPackage(uint256 id, uint256 price, uint256 daily) internal {
        packages[id] = Package({ priceWLD: price, dailyRewardYield: daily, active: true });
    }

    // ── Internal helpers ──────────────────────────────────────────────────────────

    function _pendingForPackage(address user, uint256 pkgId) internal view returns (uint256) {
        UserPackage storage up = userPackages[user][pkgId];
        if (up.units == 0) return up.pendingRewards;
        uint256 elapsed = block.timestamp - up.lastClaimTime;
        uint256 earned = up.units * packages[pkgId].dailyRewardYield * elapsed / SECONDS_PER_DAY;
        return up.pendingRewards + earned;
    }

    function _receiveViaPermit2(
        IPermit2.PermitTransferFrom calldata permit,
        bytes calldata signature,
        uint256 amount
    ) internal {
        require(permit.permitted.token == WLD_TOKEN, "Wrong token");
        IPermit2(PERMIT2).permitTransferFrom(
            permit,
            IPermit2.SignatureTransferDetails({ to: address(this), requestedAmount: amount }),
            msg.sender,
            signature
        );
    }

    // ── User Functions ────────────────────────────────────────────────────────────

    /// @notice Buy mining package(s) via Permit2 (WLD payment)
    function buyPackage(
        uint256 packageId,
        uint256 units,
        IPermit2.PermitTransferFrom calldata permit,
        bytes calldata signature
    ) external whenNotPaused {
        require(packageId < MAX_PACKAGES, "Invalid package");
        require(units > 0, "Zero units");
        Package storage pkg = packages[packageId];
        require(pkg.active, "Package inactive");

        uint256 totalCost = pkg.priceWLD * units;
        require(permit.permitted.amount >= totalCost, "Insufficient permit amount");

        _receiveViaPermit2(permit, signature, totalCost);

        // Split payment equally to owners
        uint256 half = totalCost / 2;
        IERC20(WLD_TOKEN).transfer(owners[0], half);
        IERC20(WLD_TOKEN).transfer(owners[1], totalCost - half);

        // Checkpoint rewards before adding units
        UserPackage storage up = userPackages[msg.sender][packageId];
        if (up.lastClaimTime > 0 && up.units > 0) {
            up.pendingRewards = _pendingForPackage(msg.sender, packageId);
        }
        up.lastClaimTime = block.timestamp;
        up.units += units;

        emit PackagePurchased(msg.sender, packageId, units, totalCost);
    }

    /// @notice Claim rewards for a specific package
    function claimPackageRewards(uint256 packageId) external whenNotPaused {
        require(packageId < MAX_PACKAGES, "Invalid package");
        UserPackage storage up = userPackages[msg.sender][packageId];
        require(up.units > 0 || up.pendingRewards > 0, "No mining power");

        uint256 earned = _pendingForPackage(msg.sender, packageId);
        require(earned > 0, "No rewards");

        up.pendingRewards = 0;
        up.lastClaimTime = block.timestamp;

        address rewardToken = rewardTokens[packageId];
        require(IERC20(rewardToken).balanceOf(address(this)) >= earned, "Insufficient reserve");
        IERC20(rewardToken).transfer(msg.sender, earned);

        emit RewardsClaimed(msg.sender, packageId, earned, rewardToken);
    }

    /// @notice Claim all rewards across all packages
    function claimAllRewards() external whenNotPaused {
        for (uint256 i = 0; i < MAX_PACKAGES; i++) {
            UserPackage storage up = userPackages[msg.sender][i];
            if (up.units == 0 && up.pendingRewards == 0) continue;

            uint256 earned = _pendingForPackage(msg.sender, i);
            if (earned == 0) continue;

            up.pendingRewards = 0;
            up.lastClaimTime = block.timestamp;

            address rewardToken = rewardTokens[i];
            if (IERC20(rewardToken).balanceOf(address(this)) >= earned) {
                IERC20(rewardToken).transfer(msg.sender, earned);
                emit RewardsClaimed(msg.sender, i, earned, rewardToken);
            }
        }
    }

    // ── Views ──────────────────────────────────────────────────────────────────────

    function pendingPerPackage(address user) external view returns (uint256[7] memory result) {
        for (uint256 i = 0; i < MAX_PACKAGES; i++) {
            result[i] = _pendingForPackage(user, i);
        }
    }

    function getUserPackages(address user) external view returns (UserPackage[7] memory) {
        return userPackages[user];
    }

    function getAllPackages() external view returns (Package[7] memory) {
        return packages;
    }

    function getRewardTokens() external view returns (address[7] memory) {
        return rewardTokens;
    }

    /// @notice Daily yield per package for user
    function userDailyYield(address user) external view returns (uint256[7] memory daily) {
        for (uint256 i = 0; i < MAX_PACKAGES; i++) {
            daily[i] = userPackages[user][i].units * packages[i].dailyRewardYield;
        }
    }

    // ── Owner Functions ────────────────────────────────────────────────────────────

    function setPackage(uint256 id, uint256 priceWLD, uint256 dailyYield, bool active) external onlyOwner {
        require(id < MAX_PACKAGES, "Invalid id");
        packages[id] = Package({ priceWLD: priceWLD, dailyRewardYield: dailyYield, active: active });
        emit PackageConfigured(id, priceWLD, dailyYield);
    }

    function setOwner(uint256 index, address addr) external onlyOwner {
        require(index < 2, "Invalid index");
        require(addr != address(0), "Zero address");
        owners[index] = addr;
        emit OwnerChanged(index, addr);
    }

    function pause() external onlyOwner { paused = true; emit Paused(msg.sender); }
    function unpause() external onlyOwner { paused = false; emit Unpaused(msg.sender); }

    function emergencyWithdraw(address token, uint256 amount, address to) external onlyOwner {
        require(to != address(0), "Zero to");
        IERC20(token).transfer(to, amount);
        emit EmergencyWithdraw(token, to, amount);
    }
}

contracts/UniversalStaking.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./IPermit2.sol";

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function decimals() external view returns (uint8);
}

/**
 * @title UniversalStaking
 * @notice Staking contract for World Chain tokens.
 *         - Permit2 for World App compatibility
 *         - 3 configurable owners
 *         - 2% configurable fee on stake/unstake/claim
 *         - 10% of fees go to reward fund
 *         - Market-based APY (Synthetix-style reward accumulation)
 *         - Same token for deposit and rewards
 *         - Rewards accrue per second, claimable 24/7
 *         - Pause and emergency withdraw
 */
contract UniversalStaking {
    // ── Constants ───────────────────────────────────────────────────────────────
    uint256 public constant MAX_OWNERS = 3;
    uint256 public constant MAX_FEE_BPS = 1000; // max 10%
    uint256 public constant FEE_TO_REWARD_BPS = 1000; // 10% of fees → reward fund
    uint256 public constant BPS = 10000;
    address public constant PERMIT2 = 0x000000000022D473030F116dDEE9F6B43aC78BA3;
    uint256 public constant REWARD_DURATION = 365 days;

    // ── Token ────────────────────────────────────────────────────────────────────
    address public immutable TOKEN;

    // ── Owners ───────────────────────────────────────────────────────────────────
    address[3] public owners;
    uint256 public ownerCount;

    // ── Config ───────────────────────────────────────────────────────────────────
    uint256 public stakeFeeBps = 200;   // 2%
    uint256 public unstakeFeeBps = 200; // 2%
    uint256 public claimFeeBps = 200;   // 2%
    bool public paused;

    // ── Reward State (Synthetix-style) ───────────────────────────────────────────
    uint256 public rewardRate;           // tokens per second (total to all stakers)
    uint256 public periodFinish;         // timestamp when current reward period ends
    uint256 public rewardPerTokenStored; // accumulated reward per token (scaled 1e18)
    uint256 public lastUpdateTime;       // last time rewardPerTokenStored was updated
    uint256 public totalStaked;          // total tokens staked
    uint256 public rewardReserve;        // tokens reserved for rewards (not staked)

    // ── User State ───────────────────────────────────────────────────────────────
    struct UserInfo {
        uint256 staked;
        uint256 rewardPerTokenPaid;
        uint256 pendingReward;
        uint256 stakedAt;
        uint256 lastClaimAt;
    }
    mapping(address => UserInfo) public users;

    // ── Events ───────────────────────────────────────────────────────────────────
    event Staked(address indexed user, uint256 amount, uint256 fee);
    event Unstaked(address indexed user, uint256 amount, uint256 fee);
    event Claimed(address indexed user, uint256 amount, uint256 fee);
    event RewardsDeposited(address indexed depositor, uint256 amount, uint256 newRate, uint256 periodEnd);
    event FeeConfigured(uint256 stakeFeeBps, uint256 unstakeFeeBps, uint256 claimFeeBps);
    event OwnerAdded(address indexed owner);
    event OwnerRemoved(address indexed owner);
    event Paused(address indexed by);
    event Unpaused(address indexed by);
    event EmergencyWithdraw(address indexed token, address indexed to, uint256 amount);

    // ── Modifiers ─────────────────────────────────────────────────────────────────
    modifier onlyOwner() {
        require(_isOwner(msg.sender), "Not owner");
        _;
    }

    modifier whenNotPaused() {
        require(!paused, "Paused");
        _;
    }

    modifier updateReward(address account) {
        rewardPerTokenStored = rewardPerToken();
        lastUpdateTime = lastTimeRewardApplicable();
        if (account != address(0)) {
            users[account].pendingReward = earned(account);
            users[account].rewardPerTokenPaid = rewardPerTokenStored;
        }
        _;
    }

    // ── Constructor ───────────────────────────────────────────────────────────────
    constructor(address token, address owner1) {
        require(token != address(0), "Zero token");
        require(owner1 != address(0), "Zero owner");
        TOKEN = token;
        owners[0] = owner1;
        ownerCount = 1;
    }

    // ── Internal helpers ──────────────────────────────────────────────────────────
    function _isOwner(address addr) internal view returns (bool) {
        for (uint256 i = 0; i < MAX_OWNERS; i++) {
            if (owners[i] == addr) return true;
        }
        return false;
    }

    function lastTimeRewardApplicable() public view returns (uint256) {
        return block.timestamp < periodFinish ? block.timestamp : periodFinish;
    }

    function rewardPerToken() public view returns (uint256) {
        if (totalStaked == 0) return rewardPerTokenStored;
        return rewardPerTokenStored + (
            (lastTimeRewardApplicable() - lastUpdateTime) * rewardRate * 1e18 / totalStaked
        );
    }

    function earned(address account) public view returns (uint256) {
        UserInfo storage u = users[account];
        return u.staked * (rewardPerToken() - u.rewardPerTokenPaid) / 1e18 + u.pendingReward;
    }

    /// @notice APY in basis points (dynamic, based on reward rate vs total staked)
    function apyBps() external view returns (uint256) {
        if (totalStaked == 0 || rewardRate == 0) return 0;
        // APY = (rewardRate * 365 days * BPS) / totalStaked
        return rewardRate * 365 days * BPS / totalStaked;
    }

    function _distributeOwnerFee(uint256 amount) internal {
        if (amount == 0 || ownerCount == 0) return;
        uint256 share = amount / ownerCount;
        for (uint256 i = 0; i < MAX_OWNERS; i++) {
            if (owners[i] != address(0)) {
                IERC20(TOKEN).transfer(owners[i], share);
            }
        }
    }

    function _handleFee(uint256 amount, uint256 feeBps) internal returns (uint256 net) {
        if (feeBps == 0) return amount;
        uint256 fee = amount * feeBps / BPS;
        uint256 toReward = fee * FEE_TO_REWARD_BPS / BPS;
        uint256 toOwners = fee - toReward;
        // toReward stays in contract as rewards — add to rewardReserve and update rate
        rewardReserve += toReward;
        _distributeOwnerFee(toOwners);
        return amount - fee;
    }

    // ── Permit2 helper ────────────────────────────────────────────────────────────
    function _receiveViaPermit2(
        IPermit2.PermitTransferFrom calldata permit,
        bytes calldata signature,
        uint256 expectedAmount
    ) internal {
        IPermit2(PERMIT2).permitTransferFrom(
            permit,
            IPermit2.SignatureTransferDetails({ to: address(this), requestedAmount: expectedAmount }),
            msg.sender,
            signature
        );
    }

    // ── User Functions ────────────────────────────────────────────────────────────

    /// @notice Stake tokens via Permit2
    function stake(
        IPermit2.PermitTransferFrom calldata permit,
        bytes calldata signature
    ) external whenNotPaused updateReward(msg.sender) {
        uint256 amount = permit.permitted.amount;
        require(amount > 0, "Zero amount");
        require(permit.permitted.token == TOKEN, "Wrong token");

        _receiveViaPermit2(permit, signature, amount);

        uint256 net = _handleFee(amount, stakeFeeBps);

        users[msg.sender].staked += net;
        if (users[msg.sender].stakedAt == 0) users[msg.sender].stakedAt = block.timestamp;
        users[msg.sender].lastClaimAt = block.timestamp;
        totalStaked += net;

        emit Staked(msg.sender, net, amount - net);
    }

    /// @notice Unstake tokens
    function unstake() external whenNotPaused updateReward(msg.sender) {
        UserInfo storage u = users[msg.sender];
        uint256 staked = u.staked;
        require(staked > 0, "Nothing staked");

        // Auto-claim rewards first
        uint256 pending = u.pendingReward;
        if (pending > 0) {
            uint256 netReward = _claimInternal(pending, u);
            emit Claimed(msg.sender, netReward, pending - netReward);
        }

        uint256 net = _handleFee(staked, unstakeFeeBps);
        u.staked = 0;
        u.stakedAt = 0;
        totalStaked -= staked;

        IERC20(TOKEN).transfer(msg.sender, net);
        emit Unstaked(msg.sender, net, staked - net);
    }

    /// @notice Claim accumulated rewards
    function claimRewards() external whenNotPaused updateReward(msg.sender) {
        UserInfo storage u = users[msg.sender];
        uint256 pending = u.pendingReward;
        require(pending > 0, "No rewards");

        uint256 net = _claimInternal(pending, u);
        emit Claimed(msg.sender, net, pending - net);
    }

    function _claimInternal(uint256 pending, UserInfo storage u) internal returns (uint256 net) {
        u.pendingReward = 0;
        u.lastClaimAt = block.timestamp;
        net = _handleClaimFee(pending);
        IERC20(TOKEN).transfer(msg.sender, net);
    }

    function _handleClaimFee(uint256 amount) internal returns (uint256 net) {
        if (claimFeeBps == 0) return amount;
        uint256 fee = amount * claimFeeBps / BPS;
        uint256 toReward = fee * FEE_TO_REWARD_BPS / BPS;
        uint256 toOwners = fee - toReward;
        rewardReserve += toReward;
        _distributeOwnerFee(toOwners);
        return amount - fee;
    }

    // ── Owner Functions ────────────────────────────────────────────────────────────

    /// @notice Deposit reward tokens (no permit, owner calls directly with prior approval)
    function depositRewards(uint256 amount) external onlyOwner updateReward(address(0)) {
        require(amount > 0, "Zero amount");
        IERC20(TOKEN).transferFrom(msg.sender, address(this), amount);
        rewardReserve += amount;
        _updateRewardRate();
        emit RewardsDeposited(msg.sender, amount, rewardRate, periodFinish);
    }

    function _updateRewardRate() internal {
        if (block.timestamp >= periodFinish) {
            rewardRate = rewardReserve / REWARD_DURATION;
        } else {
            uint256 remaining = periodFinish - block.timestamp;
            uint256 leftover = remaining * rewardRate;
            rewardRate = (rewardReserve + leftover) / REWARD_DURATION;
        }
        lastUpdateTime = block.timestamp;
        periodFinish = block.timestamp + REWARD_DURATION;
        // Reset rewardReserve since it's now committed to rate
        rewardReserve = 0;
    }

    function setStakeFee(uint256 bps) external onlyOwner {
        require(bps <= MAX_FEE_BPS, "Fee too high");
        stakeFeeBps = bps;
        emit FeeConfigured(stakeFeeBps, unstakeFeeBps, claimFeeBps);
    }

    function setUnstakeFee(uint256 bps) external onlyOwner {
        require(bps <= MAX_FEE_BPS, "Fee too high");
        unstakeFeeBps = bps;
        emit FeeConfigured(stakeFeeBps, unstakeFeeBps, claimFeeBps);
    }

    function setClaimFee(uint256 bps) external onlyOwner {
        require(bps <= MAX_FEE_BPS, "Fee too high");
        claimFeeBps = bps;
        emit FeeConfigured(stakeFeeBps, unstakeFeeBps, claimFeeBps);
    }

    function addOwner(address addr) external onlyOwner {
        require(addr != address(0), "Zero address");
        require(!_isOwner(addr), "Already owner");
        require(ownerCount < MAX_OWNERS, "Max owners reached");
        for (uint256 i = 0; i < MAX_OWNERS; i++) {
            if (owners[i] == address(0)) {
                owners[i] = addr;
                ownerCount++;
                emit OwnerAdded(addr);
                return;
            }
        }
    }

    function removeOwner(address addr) external onlyOwner {
        require(ownerCount > 1, "Need at least 1 owner");
        for (uint256 i = 0; i < MAX_OWNERS; i++) {
            if (owners[i] == addr) {
                owners[i] = address(0);
                ownerCount--;
                emit OwnerRemoved(addr);
                return;
            }
        }
        revert("Not found");
    }

    function pause() external onlyOwner {
        paused = true;
        emit Paused(msg.sender);
    }

    function unpause() external onlyOwner {
        paused = false;
        emit Unpaused(msg.sender);
    }

    /// @notice Emergency withdraw any ERC20 from the contract
    function emergencyWithdraw(address token, uint256 amount, address to) external onlyOwner {
        require(to != address(0), "Zero to");
        IERC20(token).transfer(to, amount);
        emit EmergencyWithdraw(token, to, amount);
    }

    // ── Views ──────────────────────────────────────────────────────────────────────

    function getStakeInfo(address user) external view returns (
        uint256 stakedAmount,
        uint256 stakedAt,
        uint256 lastClaimAt,
        uint256 pendingRewards,
        bool active
    ) {
        UserInfo storage u = users[user];
        return (u.staked, u.stakedAt, u.lastClaimAt, earned(user), u.staked > 0);
    }

    function getOwners() external view returns (address[3] memory) {
        return owners;
    }

    function contractTokenBalance() external view returns (uint256) {
        return IERC20(TOKEN).balanceOf(address(this));
    }
}

contracts/UniversalStakingV2.sol.content:
pragma solidity ^0.8.24;

import "./IPermit2.sol";

interface IERC20V2 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

contract UniversalStakingV2 {
    uint256 public constant MAX_OWNERS = 3;
    uint256 public constant MAX_FEE_BPS = 1000;
    uint256 public constant FEE_TO_REWARD_BPS = 1000;
    uint256 public constant BPS = 10000;
    uint256 public constant SCALE = 1e18;
    address public constant PERMIT2 = 0x000000000022D473030F116dDEE9F6B43aC78BA3;
    uint256 public constant REWARD_DURATION = 365 days;

    address public immutable TOKEN;
    address[3] public owners;
    uint256 public ownerCount;
    uint256 public stakeFeeBps = 500;
    uint256 public unstakeFeeBps = 500;
    uint256 public claimFeeBps = 500;
    bool public paused;
    uint256 public rewardRate;
    uint256 public periodFinish;
    uint256 public rewardPerTokenStored;
    uint256 public lastUpdateTime;
    uint256 public totalStaked;
    uint256 public rewardReserve;

    struct UserInfo {
        uint256 staked;
        uint256 rewardPerTokenPaid;
        uint256 pendingReward;
        uint256 stakedAt;
        uint256 lastClaimAt;
    }

    mapping(address => UserInfo) public users;

    event Staked(address indexed user, uint256 amount, uint256 fee);
    event Unstaked(address indexed user, uint256 amount, uint256 fee);
    event Claimed(address indexed user, uint256 amount, uint256 fee);
    event RewardsDeposited(address indexed depositor, uint256 amount, uint256 newRate, uint256 periodEnd);
    event FeeConfigured(uint256 stakeFeeBps, uint256 unstakeFeeBps, uint256 claimFeeBps);
    event OwnerAdded(address indexed owner);
    event OwnerRemoved(address indexed owner);
    event Paused(address indexed by);
    event Unpaused(address indexed by);
    event EmergencyWithdraw(address indexed token, address indexed to, uint256 amount);

    modifier onlyOwner() {
        require(_isOwner(msg.sender), "Not owner");
        _;
    }

    modifier whenNotPaused() {
        require(!paused, "Paused");
        _;
    }

    modifier updateReward(address account) {
        rewardPerTokenStored = rewardPerToken();
        lastUpdateTime = lastTimeRewardApplicable();
        if (account != address(0)) {
            users[account].pendingReward = earned(account);
            users[account].rewardPerTokenPaid = rewardPerTokenStored;
        }
        _;
    }

    constructor(address token, address owner1, address owner2) {
        require(token != address(0), "Zero token");
        require(owner1 != address(0), "Zero owner");
        TOKEN = token;
        owners[0] = owner1;
        ownerCount = 1;
        if (owner2 != address(0) && owner2 != owner1) {
            owners[1] = owner2;
            ownerCount = 2;
        }
    }

    function _isOwner(address addr) internal view returns (bool) {
        for (uint256 i = 0; i < MAX_OWNERS; i++) {
            if (owners[i] == addr) return true;
        }
        return false;
    }

    function lastTimeRewardApplicable() public view returns (uint256) {
        return block.timestamp < periodFinish ? block.timestamp : periodFinish;
    }

    function rewardPerToken() public view returns (uint256) {
        if (totalStaked == 0) return rewardPerTokenStored;
        return rewardPerTokenStored + ((lastTimeRewardApplicable() - lastUpdateTime) * rewardRate / totalStaked);
    }

    function earned(address account) public view returns (uint256) {
        UserInfo storage u = users[account];
        return u.staked * (rewardPerToken() - u.rewardPerTokenPaid) / SCALE + u.pendingReward;
    }

    function apyBps() external view returns (uint256) {
        if (totalStaked == 0 || rewardRate == 0) return 0;
        return rewardRate * REWARD_DURATION * BPS / SCALE / totalStaked;
    }

    function _safeTransfer(address to, uint256 amount) internal {
        require(IERC20V2(TOKEN).transfer(to, amount), "Transfer failed");
    }

    function _safeTransferFrom(address from, address to, uint256 amount) internal {
        require(IERC20V2(TOKEN).transferFrom(from, to, amount), "TransferFrom failed");
    }

    function _distributeOwnerFee(uint256 amount) internal {
        if (amount == 0 || ownerCount == 0) return;
        uint256 distributed;
        uint256 share = amount / ownerCount;
        for (uint256 i = 0; i < MAX_OWNERS; i++) {
            if (owners[i] != address(0)) {
                _safeTransfer(owners[i], share);
                distributed += share;
            }
        }
        uint256 remainder = amount - distributed;
        if (remainder > 0) rewardReserve += remainder;
    }

    function _handleFee(uint256 amount, uint256 feeBps) internal returns (uint256 net) {
        if (feeBps == 0) return amount;
        uint256 fee = amount * feeBps / BPS;
        uint256 toReward = fee * FEE_TO_REWARD_BPS / BPS;
        uint256 toOwners = fee - toReward;
        rewardReserve += toReward;
        _distributeOwnerFee(toOwners);
        return amount - fee;
    }

    function _receiveViaPermit2(IPermit2.PermitTransferFrom calldata permit, bytes calldata signature, uint256 expectedAmount) internal {
        IPermit2(PERMIT2).permitTransferFrom(
            permit,
            IPermit2.SignatureTransferDetails({ to: address(this), requestedAmount: expectedAmount }),
            msg.sender,
            signature
        );
    }

    function stake(IPermit2.PermitTransferFrom calldata permit, bytes calldata signature) external whenNotPaused updateReward(msg.sender) {
        uint256 amount = permit.permitted.amount;
        require(amount > 0, "Zero amount");
        require(permit.permitted.token == TOKEN, "Wrong token");
        _receiveViaPermit2(permit, signature, amount);
        uint256 net = _handleFee(amount, stakeFeeBps);
        users[msg.sender].staked += net;
        if (users[msg.sender].stakedAt == 0) users[msg.sender].stakedAt = block.timestamp;
        users[msg.sender].lastClaimAt = block.timestamp;
        totalStaked += net;
        emit Staked(msg.sender, net, amount - net);
    }

    function unstake() external whenNotPaused updateReward(msg.sender) {
        UserInfo storage u = users[msg.sender];
        uint256 staked = u.staked;
        require(staked > 0, "Nothing staked");
        uint256 pending = u.pendingReward;
        if (pending > 0) {
            uint256 netReward = _claimInternal(pending, u);
            emit Claimed(msg.sender, netReward, pending - netReward);
        }
        uint256 net = _handleFee(staked, unstakeFeeBps);
        u.staked = 0;
        u.stakedAt = 0;
        totalStaked -= staked;
        _safeTransfer(msg.sender, net);
        emit Unstaked(msg.sender, net, staked - net);
    }

    function claimRewards() external whenNotPaused updateReward(msg.sender) {
        UserInfo storage u = users[msg.sender];
        uint256 pending = u.pendingReward;
        require(pending > 0, "No rewards");
        uint256 net = _claimInternal(pending, u);
        emit Claimed(msg.sender, net, pending - net);
    }

    function _claimInternal(uint256 pending, UserInfo storage u) internal returns (uint256 net) {
        u.pendingReward = 0;
        u.lastClaimAt = block.timestamp;
        net = _handleClaimFee(pending);
        _safeTransfer(msg.sender, net);
    }

    function _handleClaimFee(uint256 amount) internal returns (uint256 net) {
        if (claimFeeBps == 0) return amount;
        uint256 fee = amount * claimFeeBps / BPS;
        uint256 toReward = fee * FEE_TO_REWARD_BPS / BPS;
        uint256 toOwners = fee - toReward;
        rewardReserve += toReward;
        _distributeOwnerFee(toOwners);
        return amount - fee;
    }

    function depositRewards(uint256 amount) external onlyOwner updateReward(address(0)) {
        require(amount > 0, "Zero amount");
        _safeTransferFrom(msg.sender, address(this), amount);
        rewardReserve += amount;
        _updateRewardRate();
        emit RewardsDeposited(msg.sender, amount, rewardRate, periodFinish);
    }

    function _updateRewardRate() internal {
        if (block.timestamp >= periodFinish) {
            rewardRate = rewardReserve * SCALE / REWARD_DURATION;
        } else {
            uint256 remaining = periodFinish - block.timestamp;
            uint256 leftover = remaining * rewardRate / SCALE;
            rewardRate = (rewardReserve + leftover) * SCALE / REWARD_DURATION;
        }
        lastUpdateTime = block.timestamp;
        periodFinish = block.timestamp + REWARD_DURATION;
        rewardReserve = 0;
    }

    function setStakeFee(uint256 bps) external onlyOwner {
        require(bps <= MAX_FEE_BPS, "Fee too high");
        stakeFeeBps = bps;
        emit FeeConfigured(stakeFeeBps, unstakeFeeBps, claimFeeBps);
    }

    function setUnstakeFee(uint256 bps) external onlyOwner {
        require(bps <= MAX_FEE_BPS, "Fee too high");
        unstakeFeeBps = bps;
        emit FeeConfigured(stakeFeeBps, unstakeFeeBps, claimFeeBps);
    }

    function setClaimFee(uint256 bps) external onlyOwner {
        require(bps <= MAX_FEE_BPS, "Fee too high");
        claimFeeBps = bps;
        emit FeeConfigured(stakeFeeBps, unstakeFeeBps, claimFeeBps);
    }

    function addOwner(address addr) external onlyOwner {
        require(addr != address(0), "Zero address");
        require(!_isOwner(addr), "Already owner");
        require(ownerCount < MAX_OWNERS, "Max owners reached");
        for (uint256 i = 0; i < MAX_OWNERS; i++) {
            if (owners[i] == address(0)) {
                owners[i] = addr;
                ownerCount++;
                emit OwnerAdded(addr);
                return;
            }
        }
    }

    function removeOwner(address addr) external onlyOwner {
        require(ownerCount > 1, "Need at least 1 owner");
        for (uint256 i = 0; i < MAX_OWNERS; i++) {
            if (owners[i] == addr) {
                owners[i] = address(0);
                ownerCount--;
                emit OwnerRemoved(addr);
                return;
            }
        }
        revert("Not found");
    }

    function pause() external onlyOwner {
        paused = true;
        emit Paused(msg.sender);
    }

    function unpause() external onlyOwner {
        paused = false;
        emit Unpaused(msg.sender);
    }

    function emergencyWithdraw(address token, uint256 amount, address to) external onlyOwner {
        require(to != address(0), "Zero to");
        require(IERC20V2(token).transfer(to, amount), "Transfer failed");
        emit EmergencyWithdraw(token, to, amount);
    }

    function getStakeInfo(address user) external view returns (uint256 stakedAmount, uint256 stakedAt, uint256 lastClaimAt, uint256 pendingRewards, bool active) {
        UserInfo storage u = users[user];
        return (u.staked, u.stakedAt, u.lastClaimAt, earned(user), u.staked > 0);
    }

    function getOwners() external view returns (address[3] memory) {
        return owners;
    }

    function contractTokenBalance() external view returns (uint256) {
        return IERC20V2(TOKEN).balanceOf(address(this));
    }
}

